// Merge all items and remove duplicates based on link
const items = $input.all();
const uniqueItems = new Map();

const keywords = /AI|Artificial Intelligence|Machine Learning|LLM|GPT|Neural Network|Software|Developer|Coding|Programming|DevOps/i;

items.forEach(item => {
  const link = item.json.link || item.json.guid;
  const title = item.json.title || '';

  // Deduplicate and Simple Keyword Filter
  if (link && !uniqueItems.has(link) && keywords.test(title)) {
    uniqueItems.set(link, item.json);
  }
});

return Array.from(uniqueItems.values()).map(i => ({ json: i }));

