// Sort by score and take top 10
const items = $input.all().map(i => {
  const content = i.json.message?.content || i.json;
  // Parse if string, handle if object
  const data = typeof content === 'string' ? JSON.parse(content) : content;

  return {
    json: {
      ...i.json,
      analysis: data
    }
  };
});

items.sort((a, b) => (b.json.analysis.score || 0) - (a.json.analysis.score || 0));

return items.slice(0, 10);

let html = '<h1>Daily Tech News Digest</h1>';

$input.all().forEach(item => {
  const title = item.json.title;
  const link = item.json.link;
  const summary = item.json.analysis.summary;
  const score = item.json.analysis.score;

  html += `
    <div style="margin-bottom: 20px; border-bottom: 1px solid #ccc; padding-bottom: 10px;">
      <h3><a href="${link}">${title}</a> <span style="font-size: 0.8em; color: #666;">(Score: ${score})</span></h3>
      <p>${summary}</p>
    </div>
  `;
});

return [{ json: { html } }];
